function fitting(xdata, ydata)
#=
    model(t, p)=(p[1]*((t)).^(p[2])).+p[3];

    p0=[0.5, 0.5, 0.5];

    fit = curve_fit(model, xdata, ydata, p0);

    f(x)=fit[1,1]*x^(fit[1, 2])+fit[1, 3];
    plot!(f);

    println("fit: ", fit);
=#
end






