function plotRatioTest(hs, five, six, j2)
    ratios=[];
    for i=1:length(six)
        push!(ratios, six[i]/five[i]);
    end
    display(plot(hs, ratios, title="order 6/order 5 result, J2="*string(j2), xaxis="h", yaxis="a_6/a_5"));
end







